func makeLabel(key: string, items: string[], idx: int): string {
    val score = items[idx].length * idx + items[0].length
    return <label
        class="label"
        data-key={key}
        data-idx={idx}
        data-score={score}
        data-valid={score > 0 && idx < items.length && !false}
    >
        {key}: {items[idx]} ({score})
    </label>
}

func makeInput(field: Field, idx: int, cfg: Config): string {
    val isValid = field.value.length > 0 && !field.error && field.value.length < cfg.maxLen
    val score = field.value.length * cfg.weights[idx] - field.penalty * cfg.factor
    return <input
        type={field.type}
        name={field.name}
        data-idx={idx}
        data-valid={isValid}
        data-score={score}
        data-flag={score > cfg.threshold && isValid && !cfg.readonly}
        data-chain={field.meta.key.length * cfg.weights[0] + score - cfg.offsets[idx]}
        disabled={cfg.readonly || field.locked || score < 0 && !cfg.allowNegative}
    />
}

func makeField(data: Form, idx: int, cfg: Config): string {
    val field = data.fields[idx]
    val lbl = makeLabel(field.label, data.options, idx)
    val input = makeInput(field, idx, cfg)
    val isValid = field.value.length > 0 && !field.error
    val score = field.value.length * cfg.weights[idx] - field.penalty

    return <div
        class="field"
        data-idx={idx}
        data-valid={isValid}
        data-score={score}
        data-flag={score > cfg.threshold && isValid && !cfg.readonly}
        data-chain={data.fields[idx].meta.key.length * cfg.weights[0] + score}
    >
        {lbl}
        {input}
        <span class="hint" data-show={!isValid && field.error && !cfg.silent}>
            {field.errorMsg}: {field.value.length} / {cfg.maxLen}
        </span>
    </div>
}

func renderForm(data: Form, cfg: Config): string {
    val total = data.fields[0].value.length + data.fields[data.fields.length - 1].value.length
    val isReady = total > 0 && !cfg.loading && data.fields.length > 0
    val field0 = makeField(data, 0, cfg)
    val field1 = makeField(data, 1, cfg)

    return <form
        class="form"
        data-ready={isReady}
        data-total={total}
        data-valid={isReady && total > cfg.minTotal && !cfg.readonly}
        data-score={total * cfg.weights[0] - cfg.threshold * data.fields.length}
    >
        <header data-count={data.fields.length} data-ready={isReady}>
            <h2>{data.title}: {total} chars</h2>
            <small data-valid={isReady && !cfg.loading}>{data.description}</small>
        </header>
        {field0}
        {field1}
        <footer
            data-valid={isReady && !cfg.readonly}
            data-score={total * cfg.factor - cfg.offset}
        >
            <button
                data-action="submit"
                data-ready={isReady}
                disabled={!isReady || cfg.readonly || cfg.loading}
            >
                Submit ({total} chars)
            </button>
        </footer>
    </form>
}
